import React, { useState } from 'react';

function PeopleWorked({ data }) {
  const [currentIndex, setCurrentIndex] = useState(0);

  if (!data || data.length === 0) return null;

  const handlePrev = () => {
    setCurrentIndex((prevIndex) => 
      prevIndex === 0 ? data.length - 1 : prevIndex - 1
    );
  };

  const handleNext = () => {
    setCurrentIndex((prevIndex) => 
      prevIndex === data.length - 1 ? 0 : prevIndex + 1
    );
  };

  const currentPerson = data[currentIndex];
  const nextPerson = data[(currentIndex + 1) % data.length];

  return (
    <section id="people-worked" className="py-12 md:py-16 bg-[#f6f1e7]">
      <div className="max-w-7xl mx-auto px-4">
        <div className="mb-8 md:mb-10">
          <p className="text-[10px] uppercase tracking-[0.4em] text-[#7b7367] font-semibold mb-3">
            People I Worked With
          </p>
          <h2
            className="text-3xl md:text-5xl text-[#1d1c19]"
            style={{ fontFamily: '"Playfair Display", "Times New Roman", serif', fontWeight: 700 }}
          >
            Testimonials
          </h2>
        </div>

        <div className="grid grid-cols-1 xl:grid-cols-[minmax(0,1.7fr)_minmax(320px,0.8fr)] gap-4 items-stretch">
          <div className="border border-[#ddd3c5] rounded-3xl bg-white overflow-hidden shadow-[0_14px_35px_rgba(17,17,17,0.06)]">
            <div className="p-5 md:p-6 min-h-[220px] md:min-h-[260px] flex items-center">
              <p className="text-base md:text-lg font-semibold text-[#4d473f] leading-relaxed max-w-3xl">
                {currentPerson.testimonial}
              </p>
            </div>

            <div className="border-t border-[#ebe3d8] p-4 md:p-5 flex items-center gap-3 bg-white">
              <div className="w-12 h-12 rounded-full overflow-hidden flex-shrink-0 bg-[#f2ece2] flex items-center justify-center text-xl">
                {currentPerson.avatar}
              </div>
              <div>
                <h4 className="text-sm md:text-base font-black text-[#1d1b18]">
                  {currentPerson.name}
                </h4>
                <p className="text-[10px] md:text-xs uppercase tracking-[0.25em] text-[#7a7265] mt-1">
                  {currentPerson.role}
                </p>
              </div>
            </div>
          </div>

          <div className="relative border border-[#ddd3c5] rounded-3xl bg-white overflow-hidden min-h-[220px] md:min-h-[260px] flex shadow-[0_14px_35px_rgba(17,17,17,0.06)]">
            <div className="flex-1 p-5 md:p-6 opacity-55 flex flex-col justify-between">
              <p className="text-sm md:text-base font-semibold text-[#625c52] leading-relaxed max-w-sm">
                {nextPerson.testimonial}
              </p>

              <div className="flex items-center gap-3 pt-6">
                <div className="w-12 h-12 rounded-full overflow-hidden flex-shrink-0 bg-[#f2ece2] flex items-center justify-center text-xl">
                  {nextPerson.avatar}
                </div>
                <div>
                  <h4 className="text-sm md:text-base font-black text-[#1d1b18]">
                    {nextPerson.name}
                  </h4>
                  <p className="text-[10px] uppercase tracking-[0.25em] text-[#7a7265] mt-1">
                    {nextPerson.role}
                  </p>
                </div>
              </div>
            </div>

            <button
              onClick={handleNext}
              className="absolute right-3 top-1/2 -translate-y-1/2 w-10 h-10 rounded-full bg-[#f2ece2] hover:bg-[#1f1d1a] text-[#1f1d1a] hover:text-white flex items-center justify-center transition-colors shadow-sm"
              aria-label="Next testimonial"
            >
              <svg className="w-4 h-4" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round">
                <path d="M10 6V5a2 2 0 0 1 2-2h0a2 2 0 0 1 2 2v1" />
                <rect x="3" y="6" width="18" height="13" rx="2" />
                <path d="M3 11h18" />
                <path d="M9 11v2a1 1 0 0 0 1 1h4a1 1 0 0 0 1-1v-2" />
              </svg>
            </button>
          </div>
        </div>
      </div>
    </section>
  );
}

export default PeopleWorked;
